from langchain_core.output_parsers import StrOutputParser
from typing import Optional

GEN_PROMPT = ChatPromptTemplate.from_messages([
    ("system", "You are an expert writer. Produce high-quality output that satisfies the objective."),
    ("human",
     "Objective: {objective}\n\n"
     "{feedback_section}"
     "Produce your output:")
])

gen_chain = GEN_PROMPT | llm | StrOutputParser()

def build_feedback_section(
    previous_output: Optional[str],
    evaluation: Optional[EvaluationResult],
) -> str:
    if previous_output is None or evaluation is None:
        return ""

    issues_text = "\n".join(f"  - {issue}" for issue in evaluation.issues)
    strengths_text = "\n".join(f"  - {s}" for s in evaluation.strengths)

    return (
        f"Previous attempt (score {evaluation.score:.2f}):\n{previous_output}\n\n"
        f"Issues to fix (be specific):\n{issues_text}\n\n"
        f"Strengths to preserve (do not regress on these):\n{strengths_text}\n\n"
    )

def generate(
    objective: str,
    previous_output: Optional[str] = None,
    evaluation: Optional[EvaluationResult] = None,
) -> str:
    feedback = build_feedback_section(previous_output, evaluation)
    return gen_chain.invoke({"objective": objective, "feedback_section": feedback})

from langchain_core.runnables import RunnableParallel

class DimensionScore(BaseModel):
    score: float = Field(ge=0.0, le=1.0)
    issues: list[str]

class MultiDimEvaluation(BaseModel):
    accuracy: DimensionScore
    clarity: DimensionScore
    completeness: DimensionScore
    tone: DimensionScore

    def overall_score(self) -> float:
        weights = {"accuracy": 0.4, "clarity": 0.25, "completeness": 0.25, "tone": 0.1}
        return sum(
            getattr(self, dim).score * w
            for dim, w in weights.items()
        )

    def weakest_dimension(self) -> str:
        return min(
            ["accuracy", "clarity", "completeness", "tone"],
            key=lambda d: getattr(self, d).score,
        )

    def all_issues(self) -> list[str]:
        issues = []
        for dim in ["accuracy", "clarity", "completeness", "tone"]:
            for issue in getattr(self, dim).issues:
                issues.append(f"[{dim}] {issue}")
        return issues

multi_eval_chain = (
    ChatPromptTemplate.from_messages([
        ("system",
         "Score the output on four dimensions (0-1 each) with specific issues per dimension.\n"
         "Return JSON matching the schema exactly."),
        ("human",
         "Objective: {objective}\n\nOutput:\n{output}\n\nEvaluate:"),
    ])
    | llm.with_structured_output(MultiDimEvaluation)
)

def multi_dim_optimizer(objective: str, max_iterations: int = 4) -> dict:
    output = generate(objective)
    best_output, best_score = output, 0.0

    for i in range(max_iterations):
        eval_result = multi_eval_chain.invoke({"objective": objective, "output": output})
        score = eval_result.overall_score()

        if score > best_score:
            best_score, best_output = score, output

        if score >= 0.85:
            break

        # Focus feedback on the weakest dimension
        weakest = eval_result.weakest_dimension()
        focused_feedback = EvaluationResult(
            score=score,
            issues=eval_result.all_issues(),
            strengths=[],
            should_stop=False,
            stop_reason=f"Focus on improving {weakest} (score: {getattr(eval_result, weakest).score:.2f})",
        )
        output = generate(objective, output, focused_feedback)

    return {"best_output": best_output, "best_score": best_score}

from collections import deque

class ConvergenceDetector:
    def __init__(self, patience: int = 2, min_delta: float = 0.02, similarity_threshold: float = 0.9):
        self.patience = patience
        self.min_delta = min_delta
        self.similarity_threshold = similarity_threshold
        self._scores: deque = deque(maxlen=patience + 1)
        self._outputs: deque = deque(maxlen=2)

    def update(self, score: float, output: str) -> None:
        self._scores.append(score)
        self._outputs.append(output)

    def is_stagnating(self) -> bool:
        if len(self._scores) < self.patience + 1:
            return False
        recent = list(self._scores)
        # No improvement over last `patience` iterations
        return all(recent[i+1] - recent[i] < self.min_delta for i in range(len(recent)-1))

    def is_repeating(self) -> bool:
        if len(self._outputs) < 2:
            return False
        a, b = list(self._outputs)
        tokens_a = set(a.lower().split())
        tokens_b = set(b.lower().split())
        if not tokens_a or not tokens_b:
            return False
        overlap = len(tokens_a & tokens_b) / len(tokens_a | tokens_b)
        return overlap > self.similarity_threshold

    def should_stop_early(self) -> tuple[bool, str]:
        if self.is_repeating():
            return True, "outputs converged (generator repeating itself)"
        if self.is_stagnating():
            return True, f"score stagnated over {self.patience} iterations"
        return False, ""

def evaluator_optimizer_with_convergence(
    objective: str,
    max_iterations: int = 5,
    score_threshold: float = 0.85,
) -> dict:
    detector = ConvergenceDetector()
    current_output, current_eval = None, None
    best_output, best_score = None, -1.0
    stop_reason = "max iterations"

    for i in range(max_iterations):
        current_output = generate(objective, current_output, current_eval)
        current_eval = evaluator_chain.invoke({
            "objective": objective,
            "output": current_output,
        })
        detector.update(current_eval.score, current_output)

        if current_eval.score > best_score:
            best_score, best_output = current_eval.score, current_output

        if current_eval.score >= score_threshold:
            stop_reason = "threshold reached"
            break

        early_stop, reason = detector.should_stop_early()
        if early_stop:
            stop_reason = reason
            break

    return {"best_output": best_output, "best_score": best_score,
            "stop_reason": stop_reason, "iterations": i + 1}
